mapper.select:
select count(*)
  from reservation
 where charger_id = #{chargerId}
   and reservation_date = #{reservationDate}
   and status in ('예약완료', '인증완료', '충전중')
   and start_time < #{endTime}
   and end_time > #{startTime}

mapper.insert:
insert into reservation (
      member_id
    , vehicle_id
    , charger_id
    , reservation_date
    , start_time
    , end_time
    , current_soc
    , target_soc
    , required_kwh
    , estimated_minutes
    , estimated_cost
    , status
    , auth_code
    , created_at
)
values (
      #{memberId}
    , #{vehicleId}
    , #{chargerId}
    , #{reservationDate}
    , #{startTime}
    , #{endTime}
    , #{currentSoc}
    , #{targetSoc}
    , #{requiredKwh}
    , #{estimatedMinutes}
    , #{estimatedCost}
    , #{status}
    , #{authCode}
    , current_timestamp
)
